function showThis() {
  console.log(this);
}

const obj = {
  name: 'My Object',
  show: showThis
};

showThis();      // window (default binding)
obj.show();      // { name: 'My Object', show: ... } (implicit binding)

const detached = obj.show;
detached();      // window again! (lost implicit binding)

const alice = { name: 'Alice' };
const bob   = { name: 'Bob' };

function greet(greeting, punctuation) {
  return `${greeting}, ${this.name}${punctuation}`;
}

console.log(greet.call(alice, 'Hello', '!'));  // 'Hello, Alice!'
console.log(greet.apply(bob, ['Hi', '?']));    // 'Hi, Bob?'

// Borrow array methods from objects:
const args = { 0: 'a', 1: 'b', length: 2 };
console.log(Array.prototype.slice.call(args, 0)); // ['a', 'b']

const alice = { name: 'Alice' };

function introduce(title) {
  return `${title} ${this.name}`;
}

const boundIntroduce = introduce.bind(alice);

console.log(boundIntroduce('Dr.'));      // 'Dr. Alice'
console.log(boundIntroduce('Prof.'));    // 'Prof. Alice'

// Even call can't change a bound function's 'this':
console.log(boundIntroduce.call({ name: 'Bob' }, 'Ms.')); // 'Ms. Alice' (ignored!)

function Timer() {
  this.seconds = 0;

  // Regular function loses 'this'
  setInterval(function() {
    this.seconds++; // this = window (wrong!)
  }, 1000);

  // Arrow function preserves 'this' from the enclosing scope
  setInterval(() => {
    this.seconds++; // this = Timer instance (correct!)
  }, 1000);
}

const t = new Timer();
// After 3 seconds, t.seconds = 3 (only the arrow version works)

function Car(make, model) {
  // 'this' is a brand new object (created by 'new')
  this.make = make;
  this.model = model;
  this.isRunning = false;

  // If you forget 'new', 'this' becomes window!
  // this.make = make would set window.make!
}

const car1 = new Car('Toyota', 'Camry');
console.log(car1.make);   // 'Toyota'
console.log(car1.model);  // 'Camry'

// Without 'new' (DANGER):
const car2 = Car('Honda', 'Civic'); // sets window.make, returns undefined
console.log(car2); // undefined
